async function sbFetch(path, opts = {}) {
  const res = await fetch(`${SB_URL}/rest/v1/${path}`, {
    ...opts,
    headers: { apikey: SB_KEY, Authorization: `Bearer ${SB_KEY}`, "Content-Type": "application/json", ...opts.headers },
  });
  if (!res.ok) throw new Error(`${res.status} ${await res.text()}`);
  return res;
}

function item(num, title, desc, source) {
  return `<div style="margin-bottom:28px;padding:20px 24px;border-radius:14px;background:rgba(124,106,255,0.03);border:1px solid rgba(124,106,255,0.08)">
<h3 style="margin:0 0 12px;font-size:16px;font-weight:800;color:#1a1730">${num}. ${title}</h3>
<p style="margin:0 0 10px;font-size:14px;line-height:1.85;color:#333">${desc}</p>
<p style="margin:0;font-size:12px;color:#999">출처: ${source}</p>
</div>`;
}

function makeBody(imageUrl, items, altText = "소셜클리핑") {
  return `<div style="margin-bottom:28px"><img src="${imageUrl}" alt="${altText}" style="width:100%;max-width:800px;border-radius:14px;display:block"></div>
${items.join("\n")}`;
}

